def permute_swap(self, nums: list[int]) -> list[list[int]]:
    nums = nums[:]
    ans, n = [], len(nums)

    def bt(i):
        if i == n:
            ans.append(nums[:])
            return
        for j in range(i, n):
            nums[i], nums[j] = nums[j], nums[i]
            bt(i + 1)
            nums[i], nums[j] = nums[j], nums[i]

    bt(0)
    return ans
